+size_t arStringLen(const void *ptr) {
+    const uint8_t *p = (const uint8_t *)ptr;
+    if (p[0] & 0x80) {
+        return ((size_t)(p[0] & 0x7F) << 8) | p[1];
+    } else {
+        size_t len = 0;
+        for (int i = 0; i < 8; i++) len = (len << 8) | p[i];
+        return len;
+    }
+}
+
+const char *arStringData(const void *ptr) {
+    const uint8_t *p = (const uint8_t *)ptr;
+    return (const char *)(p + ((p[0] & 0x80) ? 2 : 8));
